&#34;number&#34;&gt;2332.160319&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;542.356703&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0.0&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0.0&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;number&#34;&gt;1.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;&amp;quot;Tr_velo_to_cam&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;attr&#34;&gt;&amp;quot;translation&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;punctuation&#34;&gt;[&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;-5.779144404715124&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;6.037615758600886&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;1.0636424034755758&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;attr&#34;&gt;&amp;quot;rotation&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;punctuation&#34;&gt;[&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;-0.0638033225610772&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;-0.9910914864003576&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;-0.04429948490729328&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;-0.2102873406178483&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0.043997692433495696&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;-0.7987692871343754&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;0.97575114561348&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;-0.06031492538699515&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;-0.17158543199893228&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;punctuation&#34;&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;punctuation&#34;&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;дёҠйқўжҳҜ annos еҶ…зҡ„ж–Үд»¶ж јејҸ, дёәеӣҫеғҸзҡ„еҶ…/еӨ–еҸӮ, дёӢйқўжҳҜеҲҶжһҗ (&lt;code&gt;-&amp;gt;&lt;/code&gt;жүҖжҢҮеҗ‘зҡ„дёә&amp;quot;еҺҹж–ҷ&amp;quot;)&lt;/p&gt;
&lt;figure class=&#34;highlight clean&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;# annotations ж ҮжіЁ&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;annos&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  # еӣҫзүҮж–Үд»¶&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;&amp;quot;file_name&amp;quot;&lt;/span&gt; -&amp;gt; image&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  # зӣёжңәеҶ…еҸӮ&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;&amp;quot;cam_intrinsic&amp;quot;&lt;/span&gt; -&amp;gt; calib/camera_intrinsic.&lt;span class=&#34;string&#34;&gt;&amp;quot;cam_K&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  # LiDAR еҲ° Camera зҡ„еӨ–еҸӮзҹ©йҳө, еҸҚиҝҮжқҘе°ұжҳҜ Camera еҲ° LiDAR зҡ„ (зӣёжңәеӨ–еҸӮ)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;&amp;quot;Tr_velo_to_cam&amp;quot;&lt;/span&gt;-&amp;gt; calib/virtuallidar_to_camera&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h4 id=&#34;VirtualLiDAR-иҪ¬жҚўе’Ңз»„жҲҗ&#34;&gt;VirtualLiDAR-иҪ¬жҚўе’Ңз»„жҲҗ&lt;/h4&gt;
&lt;p&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/blog/Z0ADvR.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;image + annos + label/camera =&amp;gt; еӣҫеғҸзҡ„ 3D ж ҮжіЁ&lt;/p&gt;
&lt;p&gt;velodyne(зӮ№дә‘ pcd ж–Үд»¶) + label/virtuallidar =&amp;gt; зӮ№дә‘зҡ„ 3D ж ҮжіЁ&lt;/p&gt;
&lt;p&gt;иҷҡжӢҹ LiDAR еқҗж Үзі»еҲ°иҷҡжӢҹдё–з•Ңеқҗж Үзі»зҡ„иҪ¬жҚўе°ұз®ҖеҚ•дәҶ, еҸӘйңҖиҰҒйҖҡиҝҮ &lt;code&gt;calib/virtuallidar_to_world&lt;/code&gt; е°ұеҸҜд»Ҙ&lt;/p&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h4 id=&#34;ж—¶й—ҙеҗҢжӯҘ-й…ҚеҮҶй—®йўҳ&#34;&gt;ж—¶й—ҙеҗҢжӯҘ-й…ҚеҮҶй—®йўҳ&lt;/h4&gt;
&lt;p&gt;и·Ҝз«Ҝ/иҪҰз«ҜеҲҶеҲ«жңүдёӘ GPS з®ЎдҪҚзҪ®е’Ңж—¶й—ҙеҗҢжӯҘ, еҗҢдёҖз«ҜеҶ… Camera е’Ң LiDAR зҡ„ж—¶й—ҙйҖҡиҝҮ GPS жҺҲж—¶еә”иҜҘжҳҜдёҖиҮҙзҡ„&lt;/p&gt;
&lt;p&gt;жүҖд»ҘеңЁзЎ¬д»¶дёҚеҮәй—®йўҳзҡ„жғ…еҶөдёӢ, еҗҢдёҖз«Ҝзҡ„ж—¶й—ҙй—®йўҳеҸҜд»ҘдёҚз”ЁиҖғиҷ‘, еҸҜд»ҘиҖғиҷ‘и·Ёз«Ҝй—®йўҳ (дҪҶжҳҜдёӘдәәж„ҹи§ү, еңЁ GPS жҺҲж—¶еҮҶзЎ®зҡ„жғ…еҶөдёӢ, иҪҰз«ҜдёҺи·Ҝз«ҜйҖҡдҝЎи·қзҰ»жңҖиҝңд№ҹе°ұеҮ еҚҒзұі, д№ҹдёҚз”ЁиҖғиҷ‘и·Ёз«ҜеҜјиҮҙзҡ„ж—¶е·®й—®йўҳ)&lt;/p&gt;
&lt;p&gt;жҸ’дёҖеҳҙ, ж„ҹи§үж–ҮжЎЈйҮҢжүҖиҜҙзҡ„ вҖңеҲҶеҲ«д»Ҙ Camera е’Ң LiDAR ж—¶й—ҙжҲідёәеҹәеҮҶвҖқ жңүжӯ§д№ү, д»–жғіиЎЁиҫҫзҡ„еә”иҜҘжҳҜ вҖңеҗҢдёҖж—¶й—ҙжҲідёӢзҡ„ Camera дёҺ LiDAR жҳҜдёҖеҜ№вҖқ, иҖҢдёҚжҳҜиҜҙ Camera дёҺ LiDAR еҗ„иҮӘдёәж”ҝеҲҶеҲ«и®Ўж—¶&lt;/p&gt;
&lt;p&gt;еңЁж—¶й—ҙж–№йқў, йңҖиҰҒиҖғиҷ‘зҡ„еә”иҜҘжҳҜиҪҰ-и·ҜдёӨз«Ҝзҡ„йҖҡдҝЎж—¶е»¶, еҮ еҚҒ ms зҡ„зҹӯж—¶е»¶жҳҜжІЎй—®йўҳзҡ„, еҸҜд»Ҙи§ҶдёәиҪҜе®һж—¶, иҪҰз«Ҝзҡ„еҶізӯ–еҸҜд»Ҙж»һеҗҺдёҖдәӣжқҘзӯүеҫ…и·Ҝз«Ҝзҡ„жҢҮзӨә&lt;/p&gt;
&lt;p&gt;д»Һз»ҸйӘҢдёҠжқҘзңӢ, йҡҫзӮ№еә”иҜҘжҳҜеҰӮдҪ•и®©иҪҰ-и·ҜдёӨз«Ҝи®ҫеӨҮ &lt;code&gt;иҝ…йҖҹеҢ№й…ҚиҝһжҺҘ&lt;/code&gt;, ж—Ҙеёёз”Ёзҡ„жүӢжңә 4G/5G зҪ‘жӯЈеёёе°ұжҳҜеҮ еҚҒ ms е»¶иҝҹ, дҪҶжҳҜжүӢжңәдёҺеҹәз«ҷеңЁеҢ№й…ҚиҝһжҺҘйҳ¶ж®өйңҖиҰҒиҖ—иҙ№еҘҪеҮ з§’ (дёҚзҹҘйҒ“еңЁи®ҫеӨҮйҖүз”Ёж–№йқўиғҪдёҚиғҪи§ЈеҶіиҝҷй—®йўҳ)&lt;/p&gt;
&lt;hr&gt;
&lt;blockquote&gt;
&lt;p&gt;жҸҗеҮәй—®йўҳ: иҪҰз«ҜжҺҘж”¶еҲ°и·Ҝз«Ҝз»ҷзҡ„ж•°жҚ®, еҝ…з„¶жҳҜеҮ еҚҒ ms д№ӢеүҚзҡ„, жҲ‘д»¬еҸҜд»ҘиҖғиҷ‘еҒҡиҝҷдёӘй…ҚеҮҶ&lt;/p&gt;
&lt;/blockquote&gt;
&lt;ol&gt;
&lt;li&gt;еҶізӯ–ж»һеҗҺ, жҜ”еҰӮи®ҫзҪ®йҳҲеҖј 100ms, еҰӮжңӘж”¶еҲ°и·Ҝз«Ҝиҝ”еӣһзҡ„ж•°жҚ®,е°ұеҸӘз”ЁиҪҰз«Ҝзҡ„иҝӣиЎҢеҶізӯ–&lt;/li&gt;
&lt;li&gt;и®©и·Ҝз«ҜиҝӣиЎҢи·Ҝзәҝйў„жөӢ, йҖјиҝ‘е®һж—¶&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h4 id=&#34;иҷҡжӢҹй—®йўҳеҸҠеҸҢз«Ҝд»»еҠЎжөҒ&#34;&gt;иҷҡжӢҹй—®йўҳеҸҠеҸҢз«Ҝд»»еҠЎжөҒ&lt;/h4&gt;
&lt;p&gt;GPS жҳҜзІҫеҮҶеҲ°з»Ҹзә¬еәҰдҪҚзҪ®зҡ„, дёәдәҶйҳІжӯўи·Ҝз«ҜдҝЎжҒҜжі„йңІ/дҫөзҠҜйҡҗз§Ғжқғ(иҪҰз«Ҝж•°жҚ®иҮӘз”ЁжүҖд»ҘдёҚз”ЁиҪ¬жҚў), и·Ҝз«Ҝи®ҫеӨҮйңҖиҰҒжҠҠз»қеҜ№дҪҚзҪ®йҖҡиҝҮ GPS иҪ¬дёәзӣёеҜ№дҪҚзҪ® (д№ҹе°ұжҳҜиҷҡжӢҹеҢ–)&lt;/p&gt;
&lt;p&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/blog/Z0ANiM.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;иҪҰз«ҜеҒҡзҡ„жҳҜ:&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;жҺўжөӢеҲ°еүҚж–№ xx зұіеӨ„жңүиҫҶиҪҰ, и®°дёӢжқҘи·ҜеҶө&lt;/li&gt;
&lt;li&gt;иҝһжҺҘи·Ҝз«Ҝе‘ҠиҜүи·Ҝз«Ҝжң¬иҪҰ GPS, зӯүеҫ…е№¶жҺҘж”¶и·Ҝз«Ҝдј еӣһзҡ„иҷҡжӢҹдё–з•Ңеқҗж Үзі», еҜ№и·ҜеҶөжҹҘжјҸиЎҘзјә&lt;/li&gt;
&lt;li&gt;ж №жҚ®и®°дёӢзҡ„и·ҜеҶөи§„еҲ’иЎҢй©¶&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;и·Ҝз«ҜеҒҡзҡ„жҳҜ:&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;жҺўжөӢеҲ°е‘ЁеӣҙжңүиҪҰ A е’Ң B, д»Ҙи·Ҝз«Ҝи®ҫеӨҮ GPS дҪҚзҪ®дёәдёӯеҝғжһ„е»әиҷҡжӢҹдё–з•Ңеқҗж Үзі»&lt;/li&gt;
&lt;li&gt;ж”¶еҲ°жҹҗиҪҰ GPS е®һж—¶е®ҡдҪҚ/relative pose (жҜ”еҰӮ A иҪҰзҡ„), жҠҠиҷҡжӢҹдё–з•Ңеқҗж Үзі»дёӯеҝғиҪ¬дёә A иҪҰзҡ„ GPS, е№¶дј з»ҷ A&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h4 id=&#34;ж ҮжіЁй—®йўҳ&#34;&gt;ж ҮжіЁй—®йўҳ&lt;/h4&gt;
&lt;p&gt;дёӢйқўеҲҶеҲ«дёәеӣҫеғҸдёҺ LiDAR зҡ„ж ҮжіЁж–Үд»¶, жҲ‘еҺҹд»Ҙдёәзҡ„зІҫеәҰй—®йўҳд»ҘеҸҠж•°жҚ®иҪ¬жҚўжҳҜиҜҜи§Ј, е®һйҷ…дёҠжҳҜдёӨжЁЎжҖҒйғҪеҒҡдәҶж ҮжіЁ&lt;/p&gt;
