&lt;li&gt;иҙЎзҢ®еәҰеҲҶй…Қй—®йўҳ
&lt;ul&gt;
&lt;li&gt;дёҚеҗҢ component жҲ– param еҜ№жңҖз»Ҳзі»з»ҹиҫ“еҮәз»“жһңзҡ„иҙЎзҢ®&lt;/li&gt;
&lt;li&gt;еҲ©з”ЁеҒҸеҜјж•°жұӮи§ЈиҙЎзҢ®еәҰ&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;еҸ‘еұ•еҸІ
&lt;ul&gt;
&lt;li&gt;жЁЎеһӢжҸҗеҮә&lt;/li&gt;
&lt;li&gt;еҶ°жІіжңҹ&lt;/li&gt;
&lt;li&gt;еҸҚеҗ‘дј ж’ӯз®—жі•еј•иө·зҡ„еӨҚе…ҙ&lt;/li&gt;
&lt;li&gt;жөҒиЎҢеәҰйҷҚдҪҺ&lt;/li&gt;
&lt;li&gt;ж·ұеәҰеӯҰд№ еҙӣиө·&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;MMDetection
&lt;ul&gt;
&lt;li&gt;еӣҫеғҸеҲҶзұ»
&lt;ul&gt;
&lt;li&gt;жЁЎеһӢеҸ‘еұ•
&lt;ul&gt;
&lt;li&gt;LeNet-5 (1998)&lt;/li&gt;
&lt;li&gt;AlexNet (2012)&lt;/li&gt;
&lt;li&gt;VGGNet (2014)&lt;/li&gt;
&lt;li&gt;GoogleNet (2014)&lt;/li&gt;
&lt;li&gt;ResNet (2015)&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;жЁЎеһӢи®ӯз»ғ
&lt;ul&gt;
&lt;li&gt;й…ҚзҪ®ж–Үд»¶
&lt;ul&gt;
&lt;li&gt;жЁЎеһӢз»“жһ„
&lt;ul&gt;
&lt;li&gt;жЁЎеһӢжңүеҮ еұӮ&lt;/li&gt;
&lt;li&gt;жҜҸеұӮеӨҡе°‘йҖҡйҒ“ж•°&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;ж•°жҚ®йӣҶ
&lt;ul&gt;
&lt;li&gt;ж•°жҚ®йӣҶеҲ’еҲҶ
&lt;ul&gt;
&lt;li&gt;еёёз”Ёзҡ„жңү COCO ж јејҸ, &lt;code&gt;annotation/test.json -&amp;gt; test/images&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;ж•°жҚ®ж–Үд»¶и·Ҝеҫ„&lt;/li&gt;
&lt;li&gt;ж•°жҚ®еўһејәзӯ–з•Ҙ&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;и®ӯз»ғзӯ–з•Ҙ
&lt;ul&gt;
&lt;li&gt;жўҜеәҰдёӢйҷҚз®—жі•&lt;/li&gt;
&lt;li&gt;еӯҰд№ зҺҮеҸӮж•°&lt;/li&gt;
&lt;li&gt;batch_size&lt;/li&gt;
&lt;li&gt;и®ӯз»ғжҖ»иҪ®ж¬Ў&lt;/li&gt;
&lt;li&gt;еӯҰд№ зҺҮеҸҳеҢ–зӯ–з•Ҙ&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;runtime / иҝҗиЎҢж—¶
&lt;ul&gt;
&lt;li&gt;GPU&lt;/li&gt;
&lt;li&gt;еҲҶеёғејҸзҺҜеўғй…ҚзҪ®&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;дёҖдәӣиҫ…еҠ©еҠҹиғҪ
&lt;ul&gt;
&lt;li&gt;жү“еҚ°ж—Ҙеҝ—&lt;/li&gt;
&lt;li&gt;checkpoint / е®ҡж—¶дҝқеӯҳ&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;MMDetection3D&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;blockquote&gt;
&lt;p&gt;з”ұдәҺ DL жҳҜ ML зҡ„еӯҗй—®йўҳ, жүҖд»ҘжӯӨзҜҮзқҖйҮҚеҶҷ &lt;a href=&#34;../ML&#34;&gt;рҹҘө зЎ¬е•ғ-Machine-Learning&lt;/a&gt; йҮҢйқўж¶үеҸҠз”ҡе°‘зҡ„ (и§ЈиҖҰ) &lt;br&gt;
жңүдёҖдәӣ (жҜ”еҰӮжҚҹеӨұеҮҪж•°, жўҜеәҰдёӢйҷҚ) йҡ¶еұһдәҺ ML &amp;gt; DL ,жүҖд»Ҙе ҶеңЁдәҶ ML йҮҢйқў&lt;/p&gt;
&lt;/blockquote&gt;
&lt;blockquote&gt;
&lt;ul&gt;
&lt;li&gt;жң¬зҜҮжүҖз”ЁеҲ°зҡ„д»Јз ҒеңЁиҝҷ: &lt;br&gt;
&lt;a href=&#34;../../code/DL&#34;&gt;рҹ‘©вҖҚвқӨпёҸвҖҚрҹ’ӢвҖҚрҹ‘ЁCode-4-Deep-Learning&lt;/a&gt; &lt;br&gt;
&lt;a href=&#34;../../code/MM-Detection&#34;&gt;рҹҗіMM-Detection-Colab&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;ML-2-DL&#34;&gt;ML-2-DL&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;з®ҖеҚ•и§ЈйҮҠ DL еҲ°еә•еңЁеҒҡд»Җд№Ҳ?&lt;/p&gt;
&lt;p&gt;дј з»ҹ ML е°ұеғҸжҳҜеңЁж•ҷе°ҸеӯҰз”ҹеҰӮдҪ•йҖҡиҝҮдёҖзі»еҲ—&lt;code&gt;еӣәе®ҡе…¬ејҸ&lt;/code&gt;жҗһеҮәжқҘдёҖдёӘз»“жһң,еңЁе…¬ејҸдёҚеӨӘеӨҚжқӮ/иҝҗз®—йҮҸдёҚеӨӘеӨ§ж—¶, ж•ҷиө·жқҘиҝҳеҘҪ&lt;/p&gt;
&lt;p&gt;йӮЈжҖҺд№Ҳж•ҷдёҖдёӘе°ҸеӯҰз”ҹй«ҳж•°йўҳе‘ў? д№ҹжҳҜеҸҜд»Ҙи®©д»–жӯ»и®°зЎ¬иғҢе…¬ејҸзҡ„,дҪҶжҳҜж•Ҳжһңе№¶дёҚеҘҪ&lt;/p&gt;
&lt;p&gt;DL е°ұеғҸжҳҜеңЁж•ҷд»–иҪ¬жҚўжҖқжғі (еҮҪж•°,еҜјж•°,з§ҜеҲҶвҖҰ), йҒҮеҲ°йўҳзӣ®еҗҺ,е…·дҪ“еҘ—д»Җд№Ҳе…¬ејҸ, з”ұе°ҸеӯҰз”ҹиҮӘе·ұжүҫеҲ°&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;DL дёҚеғҸ ML дёҖж ·жіӣжіӣ, еҜ№жҜҸз§Қд»»еҠЎжңүй’ҲеҜ№жҖ§зҡ„и®ҫи®Ў&lt;/p&gt;
&lt;hr&gt;
&lt;div class=&#34;tabs&#34; id=&#34;дјҳзӮ№&#34;&gt;&lt;ul class=&#34;nav-tabs&#34;&gt;&lt;li class=&#34;tab active&#34;&gt;&lt;button type=&#34;button&#34; data-href=&#34;#дјҳзӮ№-1&#34;&gt;дјҳзӮ№&lt;/button&gt;&lt;/li&gt;&lt;li class=&#34;tab&#34;&gt;&lt;button type=&#34;button&#34; data-href=&#34;#дјҳзӮ№-2&#34;&gt;зјәзӮ№&lt;/button&gt;&lt;/li&gt;&lt;/ul&gt;&lt;div class=&#34;tab-contents&#34;&gt;&lt;div class=&#34;tab-item-content active&#34; id=&#34;дјҳзӮ№-1&#34;&gt;&lt;p&gt;е°ұеғҸдёҠйқўжҸҗеҲ°зҡ„, дј з»ҹ ML йңҖиҰҒдәәж•ҷз»ҷжңәеҷЁзү№еҫҒе·ҘзЁӢ (еӣәе®ҡе…¬ејҸ), жЁЎеһӢи¶ҠеӨҚжқӮ, дәәзҡ„жҸҗеҸ–ж–№жі•е’Ңзү№еҫҒз»“жһңдјҡи¶Ҡе·®&lt;/p&gt;
&lt;p&gt;DL еҜ№зү№еҫҒзҡ„еӨ„зҗҶж–№жі•/з»“жһңиҰҒдјҳдәҺдәәзұ» (жҜ”еҰӮж·ұеұӮж¬Ўдәәзұ»ж— жі•еҜҹи§үзҡ„зү№еҫҒе…ізі»)&lt;/p&gt;&lt;button type=&#34;button&#34; class=&#34;tab-to-top&#34; aria-label=&#34;scroll to top&#34;&gt;&lt;i class=&#34;fas fa-arrow-up&#34;&gt;&lt;/i&gt;&lt;/button&gt;&lt;/div&gt;&lt;div class=&#34;tab-item-content&#34; id=&#34;дјҳзӮ№-2&#34;&gt;&lt;p&gt;DL жЁЎеһӢзҡ„иғҪеҠӣжҳҜ (дәәзұ»дј жҺҲзҡ„еҹәжң¬еҠҹ + йўҳжө·жҲҳжңҜ) еҫ—жқҘзҡ„;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;еҲ·йўҳе°‘ж—¶еҸҚдёҚеҰӮеҘ—е…¬ејҸ&lt;/li&gt;
&lt;li&gt;еҹәжң¬еҠҹжһ„е»әжҲҗжң¬й«ҳ&lt;/li&gt;
&lt;li&gt;еҸҜи§ЈйҮҠжҖ§е·® (иҷҪз„¶еҹәжң¬еҠҹжҳҜдҪ ж•ҷзҡ„,дҪҶдҪ дёҚзҹҘйҒ“жңәеҷЁжҳҜз”Ёзҡ„д»Җд№ҲжӯӘй—ЁйӮӘйҒ“зҡ„еҝғжі•)&lt;/li&gt;
&lt;/ol&gt;&lt;button type=&#34;button&#34; class=&#34;tab-to-top&#34; aria-label=&#34;scroll to top&#34;&gt;&lt;i class=&#34;fas fa-arrow-up&#34;&gt;&lt;/i&gt;&lt;/button&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;зҘһз»ҸзҪ‘и·Ҝ&#34;&gt;зҘһз»ҸзҪ‘и·Ҝ&lt;/h2&gt;
&lt;p&gt;еӨ§еӨҡзҹҘеҗҚзҡ„жЁЎеһӢйғҪжҳҜеұһдәҺ &lt;code&gt;ж·ұеәҰзҘһз»ҸзҪ‘з»ң&lt;/code&gt; зҡ„, жҜ”еҰӮ CNN, RNN, GAN вҖҰ&lt;/p&gt;
&lt;h3 id=&#34;зҘһз»Ҹе…ғ-ж„ҹзҹҘеҷЁ&#34;&gt;зҘһз»Ҹе…ғ-ж„ҹзҹҘеҷЁ&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;ж„ҹзҹҘеҷЁе°ұжҳҜдёҖдёӘзҘһз»Ҹе…ғ, зҘһз»ҸзҪ‘з»ңзҡ„з»„жҲҗеҚ•е…ғ, еҸҜиҮӘеӯҰд№ дёәеӣһеҪ’/еҲҶзұ»еҷЁ&lt;/p&gt;
&lt;p&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/blog/RC0tEP.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;y&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi&gt;f&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;w&lt;/mi&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;mo&gt;вӢ…&lt;/mo&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;w&lt;/mi&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;mo&gt;вӢ…&lt;/mo&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;b&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;y = f(w1 \cdot x1 + w2 \cdot x2 + b)
&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.625em;vertical-align:-0.1944em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;y&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10764em;&#34;&gt;f&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02691em;&#34;&gt;w&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;вӢ…&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.7278em;vertical-align:-0.0833em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.6444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02691em;&#34;&gt;w&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;вӢ…&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.7278em;vertical-align:-0.0833em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;b&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;еҪ“и°ғж•ҙ &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;w&lt;/mi&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mi&gt;b&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;w,b&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8889em;vertical-align:-0.1944em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02691em;&#34;&gt;w&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.1667em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;b&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; ж—¶,еҸҜд»Ҙеҫ—еҲ°дёҚеҗҢзҡ„еҸҳдҪ“йҖ»иҫ‘иҝҗз®—(жҜ”еҰӮдёҺжҲ–йқһ);&lt;/p&gt;
&lt;p&gt;з»ҷе®ҡи®ӯз»ғж•°жҚ®йӣҶ, &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;w&lt;/mi&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mi&gt;b&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;w,b&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8889em;vertical-align:-0.1944em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02691em;&#34;&gt;w&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.1667em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;b&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; еҸҜд»ҘйҖҡиҝҮеӯҰд№ иҮӘеҠЁи°ғж•ҙ&lt;/p&gt;
&lt;hr&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;еӯҰд№ и§„еҲҷж ёеҝғжҖқжғі: &lt;code&gt;й”ҷиҜҜй©ұеҠЁ&lt;/code&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;жқғеҖјеҲқе§ӢеҢ–&lt;/li&gt;
&lt;li&gt;иҫ“е…Ҙж ·жң¬еҜ№&lt;/li&gt;
&lt;li&gt;и®Ўз®—иҫ“еҮә&lt;/li&gt;
&lt;li&gt;ж №жҚ®ж„ҹзҹҘеҷЁеӯҰд№ и§„еҲҷи°ғж•ҙжқғеҖј&lt;/li&gt;
&lt;li&gt;иҝ”еӣһеҲ°жӯҘйӘӨ 2. иҫ“е…ҘдёӢдёҖеҜ№ж ·жң¬,е‘ЁиҖҢеӨҚе§ӢзӣҙеҲ°еҜ№жүҖжңүж ·жң¬,ж„ҹзҹҘеҷЁзҡ„е®һйҷ…иҫ“еҮәдёҺжңҹжңӣиҫ“еҮәзӣёзӯү&lt;/li&gt;
&lt;/ol&gt;
