  o^1(0) &amp;amp;= sgn(W^T(0)X^1) \\
  &amp;amp;= sgn(2.5) = 1

    \\ \ \\

    W(1) &amp;amp;=W(0) + \eta \left[d^{1}-o^{1}(0)\right] X^{1} \\
  &amp;amp;= (0.5,1,-1,0)^{T} + 0.1 (- 1- 1)(-1,1,-2,0)^{T} \\
  &amp;amp;= \left(\mathbf{0.7,0.8,-0.6,0)^{T}}\right.

    \\ \ \\

